// src/Profile.jsx
import React from "react";
import { useNavigate } from "react-router-dom";

const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function Profile() {
  const navigate = useNavigate();

  const menuButtonStyle = {
    minHeight: 80,
    background: "#ffffff",
    borderRadius: 16,
    boxShadow: "0 3px 14px rgba(0,0,0,0.1)",
    border: `2px solid ${lightGreen}`,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontWeight: 600,
    fontSize: 18,
    color: green,
    cursor: "pointer",
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 20,
      }}
    >
      <div
        style={{
          width: "100%",
          maxWidth: 420,
          background: "#ffffff",
          borderRadius: 20,
          padding: 20,
          boxShadow: "0 8px 24px rgba(0,0,0,0.15)",
        }}
      >
        {/* No Logo, No Employee ID */}

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(2,1fr)",
            gap: 14,
          }}
        >
          <button style={menuButtonStyle} onClick={() => navigate("/dashboard")}>
            Dashboard
          </button>
          <button style={menuButtonStyle} onClick={() => navigate("/addnew")}>
            Add New
          </button>
          <button style={menuButtonStyle} onClick={() => navigate("/history")}>
            History
          </button>
          <button style={menuButtonStyle} onClick={() => navigate("/tools")}>
            Tools
          </button>
        </div>
      </div>
    </div>
  );
}
